import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { connectWallet } from '../utils/walletConnector';

const Login = () => {
  const [address, setAddress] = useState('');
  const [network, setNetwork] = useState('1'); // По умолчанию Ethereum
  const [walletType, setWalletType] = useState('Trust Wallet'); // По умолчанию Trust Wallet
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');

  const { login } = useAuth();
  const navigate = useNavigate();

  // Определяем доступные кошельки в зависимости от выбранной сети
  const getAvailableWallets = () => {
    if (network === '1') { // Ethereum
      return ['Trust Wallet'];
    } else if (network === '2') { // TON
      return ['Trust Wallet', 'Tonkeeper'];
    }
    return ['Trust Wallet'];
  };

  // Обработчик изменения сети
  const handleNetworkChange = (e) => {
    const newNetwork = e.target.value;
    setNetwork(newNetwork);

    // Если выбран Ethereum и текущий кошелек - Tonkeeper, меняем на Trust Wallet
    if (newNetwork === '1' && walletType === 'Tonkeeper') {
      setWalletType('Trust Wallet');
    }
  };

  // Обработчик нажатия на кнопку подключения кошелька
  const handleWalletConnect = async (e) => {
    e.preventDefault();

    try {
      setLoading(true);
      setError('');

      // Определение сети (ETH или TON)
      const networkType = network === '1' ? 'ETH' : 'TON';

      // Подключение к кошельку и получение адреса и подписи
      const { address, signature } = await connectWallet(networkType, walletType);

      // Установка адреса в форму
      setAddress(address);

      // Если получен адрес и подпись, выполняем вход
      if (address && signature) {
        await login(address, network, signature, walletType);

        setSuccess(`Вход через ${walletType} выполнен успешно!`);

        // Перенаправляем пользователя на страницу профиля
        setTimeout(() => {
          navigate('/profile');
        }, 1500);
      }
    } catch (error) {
      console.error('Ошибка при подключении кошелька:', error);
      setError(error.message || 'Ошибка при подключении кошелька');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <div className="card" style={{ maxWidth: '500px', margin: '40px auto' }}>
        <h2>Вход через криптокошелек</h2>

        {error && <div className="alert alert-danger">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={handleWalletConnect}>
          <div className="form-group">
            <label htmlFor="network" className="form-label">
              Сеть
            </label>
            <select
              id="network"
              className="form-control"
              value={network}
              onChange={handleNetworkChange}
              disabled={loading}
            >
              <option value="1">Ethereum</option>
              <option value="2">TON</option>
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="walletType" className="form-label">
              Тип кошелька
            </label>
            <select
              id="walletType"
              className="form-control"
              value={walletType}
              onChange={(e) => setWalletType(e.target.value)}
              disabled={loading}
            >
              {getAvailableWallets().map(wallet => (
                <option key={wallet} value={wallet}>
                  {wallet}
                </option>
              ))}
            </select>
          </div>

          <button
            type="submit"
            className="btn"
            style={{ width: '100%' }}
            disabled={loading}
          >
            {loading ? 'Подключение...' : `Войти через ${walletType}`}
          </button>
        </form>

        <div style={{ marginTop: '20px', textAlign: 'center', fontSize: '0.9rem' }}>
          <p>
            Выберите сеть и тип кошелька для входа:
            <br />
            - Для Ethereum доступен только Trust Wallet.
            <br />
            - Для TON доступны Trust Wallet и Tonkeeper.
          </p>
          <p style={{ marginTop: '10px', fontStyle: 'italic' }}>
            <strong>Примечание:</strong> Если у вас не установлено нужное расширение или приложение,
            <br />система предложит его установить.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
